const stats = $('Query Stats').first().json;
const recent = $('Last 10 Processed').all().map(i => i.json);
const failures = $('Failed Companies').all().map(i => i.json);

const total = parseInt(stats.total_rows) || 0;
const enriched = parseInt(stats.enriched) || 0;
const failed = parseInt(stats.failed) || 0;
const failedRetry = parseInt(stats.failed_retry) || 0;
const fixedByRetry = parseInt(stats.fixed_by_retry) || 0;
const TARGET_TIER1 = 915;
const TARGET_TIER2 = 798;
const TARGET_TIER3 = 4410;
const TARGET_ALL = 6123;

const t1 = parseInt(stats.tier1) || 0;
const t2 = parseInt(stats.tier2) || 0;
const t3 = parseInt(stats.tier3) || 0;

const progress = ((total / TARGET_ALL) * 100).toFixed(1);
const totalFailing = failed + failedRetry;
const successRate = total > 0 ? (((total - totalFailing) / total) * 100).toFixed(1) : '0';
const avgSec = stats.avg_sec || 'N/A';
const remaining = TARGET_ALL - total;
const etaHours = remaining > 0 ? ((remaining * (parseFloat(avgSec || 5) + 15)) / 3600).toFixed(1) : '0';

return { json: {
  '📊 PIPELINE MONITOR': '════════════════',
  progress: `${total} / ${TARGET_ALL} (${progress}%)`,
  enriched,
  failed_pending: failed,
  failed_after_retry: failedRetry,
  fixed_by_retry: fixedByRetry,
  success_rate: `${successRate}%`,
  avg_duration: `${avgSec}s per company`,
  remaining,
  eta: `~${etaHours} hours`,
  '📈 BY TIER': '════════════════',
  tier1: `${t1} / ${TARGET_TIER1} (${((t1/TARGET_TIER1)*100).toFixed(1)}%)`,
  tier2: `${t2} / ${TARGET_TIER2} (${((t2/TARGET_TIER2)*100).toFixed(1)}%)`,
  tier3: `${t3} / ${TARGET_TIER3} (${((t3/TARGET_TIER3)*100).toFixed(1)}%)`,
  '⏱️ TIMING': '════════════════',
  started_at: stats.started_at || 'N/A',
  last_updated: stats.last_updated || 'N/A',
  avg_fields: stats.avg_fields || 'N/A',
  '📋 LAST 10': '════════════════',
  recent: recent.map(r => `${r.ruc} | ${(r.razon_social||'').substring(0,35)} | ${r.status} | ${r.fields} fields | ${r.tier}`),
  '🔄 RETRIES': '════════════════',
  retry_summary: `${fixedByRetry} fixed | ${failedRetry} still failing | ${failed} pending retry`,
  '❌ FAILURES': `${totalFailing} total`,
  failed_list: failures.map(f => `${f.ruc} | ${(f.razon_social||'').substring(0,30)} | ${f.status} | ${f.error || 'no detail'}${f.retry_at ? ' | retried: ' + f.retry_at.substring(0,16) : ''}`)
}};
